import java.time.LocalDate;

public class Main {
    public static void main(String[] args) {
        RentalSystem sys = new RentalSystem();
        Location loc = new Location("L1", "Main", "1 St");
        Vehicle suv = sys.createVehicle("SUV", "V1", "T", "RAV4", 2024, "P1", 100.00, loc);
        sys.addVehicle(suv);
        Customer cust = new Customer("C1", "Alice", "a@e", "555", "DL1");
        Reservation r = new Reservation.Builder(cust, suv).startDate(LocalDate.of(2026,5,15)).endDate(LocalDate.of(2026,5,18)).pickupLocation(loc).build();
        sys.makeReservation(r);
        if (suv.isAvailable()) { System.out.println("FAIL_STATE_PRE"); return; }
        Bill bill = sys.completeReservation(r);
        if (bill == null) { System.out.println("FAIL_BILL"); return; }
        if (suv.isAvailable() && r.getStatus() == Reservation.Status.COMPLETED) System.out.println("COMPLETE_OK");
        else System.out.println("COMPLETE_FAIL");
    }
}

