import java.util.List;

public class Main {
    public static void main(String[] args) {
        RentalSystem sys = new RentalSystem();
        Location loc1 = new Location("L1", "Downtown", "1 St");
        Location loc2 = new Location("L2", "Airport", "2 St");
        sys.addVehicle(sys.createVehicle("SUV", "V1", "T", "RAV4", 2024, "P1", 100.00, loc1));
        sys.addVehicle(sys.createVehicle("SUV", "V2", "F", "Explorer", 2023, "P2", 90.00, loc2));
        sys.addVehicle(sys.createVehicle("CAR", "V3", "T", "Camry", 2024, "P3", 50.00, loc1));
        List<Vehicle> suvs = sys.searchAvailable("SUV");
        List<Vehicle> dtSUVs = sys.searchAvailable("SUV", loc1);
        if (suvs.size() == 2 && dtSUVs.size() == 1 && dtSUVs.get(0).getVehicleId().equals("V1")) System.out.println("SEARCH_OK");
        else System.out.println("SEARCH_FAIL");
    }
}
